  1→import { createId } from '../lib/id';
  2→import { defaultCategorySeeds } from './defaultCategories';
  3→
  4→export type CartStatus = 'planning' | 'shopping' | 'completed';
  5→
  6→export type FulfillmentAnimationState = 0 | 1 | 2 | 3 | 4 | 5;
  7→
  8→export interface PricePerUnit {
  9→  priceValue: number;
 10→  unit: string;
 11→}
 12→
 13→export interface PriceOption {
 14→  id: string;
 15→  store: string;
 16→  pricePerUnit: PricePerUnit;
 17→}
 18→
 19→export interface Store {
 20→  id: string;
 21→  name: string;
 22→  createdAt: string;
 23→}
 24→
 25→export interface Item {
 26→  id: string;
 27→  name: string;
 28→  categoryId: string;
 29→  priceOptions: PriceOption[];
 30→  createdAt: string;
 31→  isTemporaryShoppingItem: boolean;
 32→  shoppingPrice: number | null;
 33→  shoppingUnit: string | null;
 34→  isOnSale: boolean;
 35→  notes: string | null;
 36→  saleType: string | null;
 37→  discountValue: number | null;
 38→  regularPrice: number | null;
 39→  isDeleted: boolean;
 40→  deletedAt: string | null;
 41→  deletedFromCategoryName: string | null;
 42→  isPlanSuppressed: boolean;
 43→  planSuppressedAt: string | null;
 44→  planSuppressedReason: string | null;
 45→}
 46→
 47→export interface Category {
 48→  uid: string;
 49→  name: string;
 50→  emoji: string | null;
 51→  sortOrder: number;
 52→  colorHex: string | null;
 53→  isPlanSuppressed: boolean;
 54→  planSuppressedAt: string | null;
 55→  planSuppressedReason: string | null;
 56→  items: Item[];
 57→}
 58→
 59→export interface DeletedCartItemSnapshot {
 60→  id: string;
 61→  cartId: string;
 62→  quantity: number;
 63→  plannedStore: string;
 64→  plannedPrice: number | null;
 65→  plannedUnit: string | null;
 66→  actualStore: string | null;
 67→  actualPrice: number | null;
 68→  actualQuantity: number | null;
 69→  actualUnit: string | null;
 70→  wasEditedDuringShopping: boolean;
 71→  wasFulfilled: boolean;
 72→  itemId: string | null;
 73→}
 74→
 75→export interface CartItem {
 76→  id: string;
 77→  addedAt: string | null;
 78→  itemId: string;
 79→  quantity: number;
 80→  isFulfilled: boolean;
 81→  isSkippedDuringShopping: boolean;
 82→  plannedStore: string;
 83→  plannedPrice: number | null;
 84→  plannedUnit: string | null;
 85→  actualStore: string | null;
 86→  actualPrice: number | null;
 87→  actualQuantity: number | null;
 88→  actualUnit: string | null;
 89→  wasEditedDuringShopping: boolean;
 90→  isShoppingOnlyItem: boolean;
 91→  shoppingOnlyName: string | null;
 92→  shoppingOnlyStore: string | null;
 93→  shoppingOnlyPrice: number | null;
 94→  shoppingOnlyUnit: string | null;
 95→  shoppingOnlyCategory: string | null;
 96→  vaultItemNameSnapshot: string | null;
 97→  vaultItemCategorySnapshot: string | null;
 98→  originalPlanningQuantity: number | null;
 99→  addedDuringShopping: boolean;
100→  fulfillmentAnimationState: FulfillmentAnimationState;
101→  fulfillmentStartTime: string | null;
102→  shouldShowCheckmark: boolean;
103→  shouldStrikethrough: boolean;
104→  isOnSale: boolean;
105→  notes: string | null;
106→  saleType: string | null;
107→  discountValue: number | null;
108→  regularPrice: number | null;
109→}
110→
111→export interface Cart {
112→  id: string;
113→  name: string;
114→  budget: number;
115→  fulfillmentStatus: number;
116→  createdAt: string;
117→  updatedAt: string;
118→  startedAt: string | null;
119→  completedAt: string | null;
120→  status: CartStatus;
121→  isDeleted: boolean;
122→  deletedAt: string | null;
123→  cartItems: CartItem[];
124→}
125→
126→export interface Vault {
127→  uid: string;
128→  categories: Category[];
129→  carts: Cart[];
130→  stores: Store[];
131→  deletedItems: Item[];
132→  deletedCarts: Cart[];
133→  deletedCartItemSnapshots: DeletedCartItemSnapshot[];
134→}
135→
136→export interface User {
137→  id: string;
138→  name: string;
139→}
140→
141→export interface PreferencesState {
142→  hasCompletedOnboarding: boolean;
143→  userName: string;
144→  hasPromptedForNameAfterOnboarding: boolean;
145→  hasPromptedForNameAfterVaultCelebration: boolean;
146→  hasShownAddItemGuideAfterName: boolean;
147→  isPro: boolean;
