170→  name: string;
171→  store: string;
172→  price: number;
173→  unit: string;
174→}
175→
176→export interface CreateCartInput {
177→  name: string;
178→  budget: number;
179→  selectedItems: Array<{
180→    itemId: string;
181→    quantity: number;
182→    selectedStore?: string | null;
183→  }>;
184→}
185→
186→export interface DashboardSummary {
187→  activeCarts: Cart[];
188→  completedCarts: Cart[];
189→  totalSpent: number;
190→  overBudgetCount: number;
191→  itemCount: number;
192→}
193→
194→export function createInitialAppState(): VaultAppState {
195→  const categories: Category[] = defaultCategorySeeds.map((seed, index) => ({
196→    uid: seed.slug,
197→    name: seed.title,
198→    emoji: seed.emoji,
199→    sortOrder: index,
200→    colorHex: seed.pastelHex,
201→    isPlanSuppressed: false,
202→    planSuppressedAt: null,
203→    planSuppressedReason: null,
204→    items: [],
205→  }));
206→
207→  return {
208→    schemaVersion: 1,
209→    user: {
210→      id: createId('user'),
211→      name: 'Default User',
