  2→import {
  3→  Alert,
  4→  Pressable,
  5→  ScrollView,
  6→  StyleSheet,
  7→  Text,
  8→  TextInput,
  9→  View,
 10→} from 'react-native';
 11→
 12→import { defaultCategorySeeds } from '../../domain/defaultCategories';
 13→import { useAppStore } from '../../state/useAppStore';
 14→import { colors } from '../../theme/colors';
 15→
 16→const steps = ['Welcome', 'Store', 'First item'] as const;
 17→
 18→export function OnboardingFlow() {
 19→  const completeOnboarding = useAppStore(state => state.completeOnboarding);
 20→  const [stepIndex, setStepIndex] = useState(0);
 21→  const [userName, setUserName] = useState('');
 22→  const [storeName, setStoreName] = useState('');
 23→  const [itemName, setItemName] = useState('');
 24→  const [itemPrice, setItemPrice] = useState('4.99');
 25→  const [itemUnit, setItemUnit] = useState('each');
 26→  const [categoryId, setCategoryId] = useState(defaultCategorySeeds[0].slug);
 27→
 28→  const selectedCategory = useMemo(
 29→    () => defaultCategorySeeds.find(category => category.slug === categoryId) ?? defaultCategorySeeds[0],
 30→    [categoryId]
 31→  );
 32→
 33→  const next = async () => {
 34→    if (stepIndex === 0) {
 35→      if (!userName.trim()) {
 36→        Alert.alert('Name required', 'Enter the name Grock should use on your home screen.');
 37→        return;
 38→      }
 39→
 40→      setStepIndex(1);
 41→      return;
 42→    }
 43→
 44→    if (stepIndex === 1) {
 45→      if (!storeName.trim()) {
 46→        Alert.alert('Store required', 'Add the store you use most often.');
 47→        return;
 48→      }
 49→
 50→      setStepIndex(2);
 51→      return;
 52→    }
 53→
 54→    if (!itemName.trim() || !itemUnit.trim()) {
 55→      Alert.alert('First item required', 'Add one item so the vault starts populated.');
 56→      return;
 57→    }
 58→
 59→    const parsedPrice = Number(itemPrice);
 60→    if (!Number.isFinite(parsedPrice) || parsedPrice <= 0) {
 61→      Alert.alert('Invalid price', 'Enter a valid price for the first item.');
 62→      return;
 63→    }
 64→
 65→    await completeOnboarding({
 66→      userName,
 67→      primaryStore: storeName,
 68→      firstItemName: itemName,
 69→      firstItemPrice: parsedPrice,
 70→      firstItemUnit: itemUnit,
 71→      firstCategoryId: categoryId,
 72→    });
 73→  };
 74→
 75→  return (
 76→    <ScrollView contentContainerStyle={styles.container}>
 77→      <Text style={styles.brand}>Grock</Text>
 78→      <Text style={styles.title}>Plan, shop, and track every grocery run.</Text>
 79→      <Text style={styles.subtitle}>
 80→        This React Native migration keeps the same core flow as the SwiftUI app:
 81→        welcome, primary store, and your first saved item.
 82→      </Text>
 83→
 84→      <View style={styles.stepRow}>
 85→        {steps.map((label, index) => (
 86→          <View key={label} style={[styles.stepPill, index === stepIndex && styles.stepPillActive]}>
 87→            <Text style={[styles.stepText, index === stepIndex && styles.stepTextActive]}>{label}</Text>
 88→          </View>
 89→        ))}
 90→      </View>
 91→
 92→      {stepIndex === 0 ? (
 93→        <View style={styles.card}>
 94→          <Text style={styles.cardTitle}>Who is this vault for?</Text>
 95→          <TextInput
 96→            style={styles.input}
 97→            placeholder="Your name"
 98→            placeholderTextColor={colors.mutedInk}
 99→            value={userName}
100→            onChangeText={setUserName}
101→          />
102→        </View>
103→      ) : null}
104→
