    borderColor: colors.line,
    backgroundColor: colors.canvas,
    paddingHorizontal: 14,
    paddingVertical: 12,
    color: colors.ink,
  },
  row: {
    flexDirection: 'row',
    gap: 10,
  },
  emojiInput: {
    width: 64,
    textAlign: 'center',
  },
  flexInput: {
    flex: 1,
  },
  primaryButton: {
    alignItems: 'center',
    borderRadius: 16,
    backgroundColor: colors.brand,
    paddingVertical: 14,
  },
  primaryButtonText: {
    color: colors.surface,
    fontWeight: '800',
  },
  chipRow: {
    gap: 10,
  },
  chip: {
    borderRadius: 999,
    paddingHorizontal: 14,
    paddingVertical: 10,
    backgroundColor: colors.surfaceAlt,
    borderWidth: 1,
    borderColor: colors.line,
  },
  chipActive: {
    borderColor: colors.brand,
    backgroundColor: '#ffe4d1',
  },
  chipText: {
    color: colors.ink,
    fontWeight: '700',
  },
  itemRow: {
    gap: 10,
    paddingVertical: 12,
    borderTopWidth: 1,
    borderTopColor: colors.line,
  },
  itemMeta: {
    gap: 4,
  },
  itemName: {
    color: colors.ink,
    fontWeight: '700',
    fontSize: 16,
  },
  itemPrice: {
    color: colors.mutedInk,
  },
  itemActions: {
    flexDirection: 'row',
    alignItems: 'center',
    justifyContent: 'space-between',
    gap: 12,
  },
  secondaryButton: {
    borderRadius: 14,
