import Purchases, { CustomerInfo, PurchasesOffering } from 'react-native-purchases';

export interface SubscriptionSnapshot {
  isConfigured: boolean;
  isPro: boolean;
  isLoading: boolean;
  errorMessage: string | null;
  currentOffering: PurchasesOffering | null;
  customerInfo: CustomerInfo | null;
}

class SubscriptionService {
  private configured = false;

  async refresh(previous: SubscriptionSnapshot): Promise<SubscriptionSnapshot> {
    if (!this.configured) {
      return {
        ...previous,
        isConfigured: false,
        isLoading: false,
        errorMessage: 'RevenueCat is not configured in the React Native workspace yet.',
        currentOffering: null,
      };
    }

    try {
      const [offerings, customerInfo] = await Promise.all([
        Purchases.getOfferings(),
        Purchases.getCustomerInfo(),
      ]);

      const currentOffering = offerings.current ?? null;
      const isPro = Boolean(customerInfo.entitlements.active.pro);

      return {
        isConfigured: true,
        isLoading: false,
        errorMessage: null,
        currentOffering,
        customerInfo,
        isPro,
      };
    } catch (error) {
      return {
        ...previous,
        isConfigured: this.configured,
        isLoading: false,
        errorMessage: error instanceof Error ? error.message : 'Failed to refresh subscription state.',
      };
    }
  }
}

export const subscriptionService = new SubscriptionService();

export const emptySubscriptionSnapshot: SubscriptionSnapshot = {
  isConfigured: false,
  isPro: false,
  isLoading: false,
  errorMessage: null,
  currentOffering: null,
  customerInfo: null,
};

