import {
  completeOnboardingState,
  computeCartTotal,
  createCartItemFromVaultItem,
  createInitialAppState,
} from '../src/domain/models';

describe('domain model helpers', () => {
  test('completeOnboardingState seeds the selected store and first item', () => {
    const initial = createInitialAppState();
    const next = completeOnboardingState(initial, {
      userName: 'John',
      primaryStore: 'Costco',
      firstItemName: 'Milk',
      firstItemPrice: 4.99,
      firstItemUnit: 'gallon',
      firstCategoryId: 'dairyEggs',
    });

    expect(next.preferences.hasCompletedOnboarding).toBe(true);
    expect(next.user.name).toBe('John');
    expect(next.vault.stores[0]?.name).toBe('Costco');
    expect(next.vault.categories.find(category => category.uid === 'dairyEggs')?.items[0]?.name).toBe('Milk');
  });

  test('computeCartTotal uses planned pricing for planning carts', () => {
    const state = createInitialAppState();
    state.vault.stores.push({
      id: 'store_1',
      name: 'Target',
      createdAt: new Date().toISOString(),
    });
    state.vault.categories[0].items.push({
      id: 'item_1',
      name: 'Apples',
      categoryId: state.vault.categories[0].uid,
      priceOptions: [
        {
          id: 'price_1',
          store: 'Target',
          pricePerUnit: {
            priceValue: 2.5,
            unit: 'lb',
          },
        },
      ],
      createdAt: new Date().toISOString(),
      isTemporaryShoppingItem: false,
      shoppingPrice: null,
      shoppingUnit: null,
      isOnSale: false,
      notes: null,
      saleType: null,
      discountValue: null,
      regularPrice: null,
      isDeleted: false,
      deletedAt: null,
      deletedFromCategoryName: null,
      isPlanSuppressed: false,
      planSuppressedAt: null,
      planSuppressedReason: null,
    });

    const cartItem = createCartItemFromVaultItem(state.vault, 'item_1', 3, 'Target');

    const total = computeCartTotal(state.vault, {
      id: 'cart_1',
      name: 'Groceries',
      budget: 20,
      fulfillmentStatus: 0,
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString(),
      startedAt: null,
      completedAt: null,
      status: 'planning',
      isDeleted: false,
      deletedAt: null,
      cartItems: [cartItem],
    });

    expect(total).toBe(7.5);
  });
});

