$target = Join-Path $PSScriptRoot "..\node_modules\@react-native\gradle-plugin\settings.gradle.kts"
$resolvedTarget = [System.IO.Path]::GetFullPath($target)
$pluginRoot = Split-Path $resolvedTarget -Parent

if (-not (Test-Path $resolvedTarget)) {
  Write-Host "React Native Gradle plugin settings file not found. Skipping patch."
  exit 0
}

$content = Get-Content $resolvedTarget -Raw
$line = 'plugins { id("org.gradle.toolchains.foojay-resolver-convention").version("0.5.0") }'
$replacement = '// Foojay resolver disabled by Grock RN workspace patch. Local JDK toolchains are used instead.'

if ($content.Contains($replacement)) {
  Write-Host "React Native Gradle plugin settings file already patched."
} elseif ($content.Contains($line)) {
  $patched = $content.Replace($line, $replacement)
  Set-Content -Path $resolvedTarget -Value $patched -NoNewline
  Write-Host "Patched React Native Gradle plugin to disable Foojay toolchain resolver."
} else {
  Write-Host "Expected Foojay resolver line was not found. Continuing with toolchain patch."
}

$toolchainFiles = @(
  "react-native-gradle-plugin\build.gradle.kts",
  "settings-plugin\build.gradle.kts",
  "shared\build.gradle.kts",
  "shared-testutil\build.gradle.kts"
)

foreach ($relativePath in $toolchainFiles) {
  $file = Join-Path $pluginRoot $relativePath
  if (-not (Test-Path $file)) {
    continue
  }

  $toolchainContent = Get-Content $file -Raw
  if ($toolchainContent.Contains("jvmToolchain(17)")) {
    $toolchainPatched = $toolchainContent.Replace("jvmToolchain(17)", "jvmToolchain(21)")
    Set-Content -Path $file -Value $toolchainPatched -NoNewline
    Write-Host "Updated Kotlin JVM toolchain to 21 in $relativePath"
  }
}

$sqliteFiles = @(
  "..\node_modules\react-native-sqlite-storage\platforms\android\build.gradle",
  "..\node_modules\react-native-sqlite-storage\platforms\android-native\build.gradle"
)

foreach ($relativePath in $sqliteFiles) {
  $file = [System.IO.Path]::GetFullPath((Join-Path $PSScriptRoot $relativePath))
  if (-not (Test-Path $file)) {
    continue
  }

  $sqliteContent = Get-Content $file -Raw
  if ($sqliteContent.Contains("jcenter()")) {
    $sqlitePatched = $sqliteContent.Replace("jcenter()", "mavenCentral()")
    Set-Content -Path $file -Value $sqlitePatched -NoNewline
    Write-Host "Replaced jcenter() with mavenCentral() in $file"
  }
}

$lottieGradle = [System.IO.Path]::GetFullPath((Join-Path $PSScriptRoot "..\node_modules\lottie-react-native\android\build.gradle"))
if (Test-Path $lottieGradle) {
  $lottieContent = Get-Content $lottieGradle -Raw

  if (-not $lottieContent.Contains("sourceCompatibility JavaVersion.VERSION_21")) {
    $anchor = "    sourceSets {"
    $compileOptionsBlock = @"
    compileOptions {
        sourceCompatibility JavaVersion.VERSION_21
        targetCompatibility JavaVersion.VERSION_21
    }

"@

    if ($lottieContent.Contains($anchor)) {
      $lottiePatched = $lottieContent.Replace($anchor, $compileOptionsBlock + $anchor)
      Set-Content -Path $lottieGradle -Value $lottiePatched -NoNewline
      Write-Host "Aligned lottie-react-native Java compile target to 21."
    }
  }
}

$nodeModulesRoot = [System.IO.Path]::GetFullPath((Join-Path $PSScriptRoot "..\node_modules"))
if (Test-Path $nodeModulesRoot) {
  $gradleFiles = Get-ChildItem $nodeModulesRoot -Recurse -File -Include *.gradle,*.gradle.kts
  foreach ($file in $gradleFiles) {
    $content = Get-Content $file.FullName -Raw
    if ($null -eq $content) {
      continue
    }
    $updated = $content.Replace("JavaVersion.VERSION_1_8", "JavaVersion.VERSION_21")
    $updated = $updated.Replace("JavaVersion.VERSION_17", "JavaVersion.VERSION_21")
    $updated = $updated.Replace("jvmToolchain(17)", "jvmToolchain(21)")

    if ($updated -ne $content) {
      Set-Content -Path $file.FullName -Value $updated -NoNewline
      Write-Host "Aligned Gradle JVM target to 21 in $($file.FullName)"
    }
  }
}

