336→  const activeCarts = state.vault.carts.filter(cart => !cart.isDeleted && cart.status !== 'completed');
337→  const completedCarts = state.vault.carts.filter(cart => !cart.isDeleted && cart.status === 'completed');
338→  const totalSpent = completedCarts.reduce((sum, cart) => sum + computeCartTotal(state.vault, cart), 0);
339→  const overBudgetCount = completedCarts.filter(cart => computeCartTotal(state.vault, cart) > cart.budget).length;
340→  const itemCount = state.vault.categories.reduce((sum, category) => sum + category.items.length, 0);
341→
342→  return {
343→    activeCarts,
344→    completedCarts,
345→    totalSpent,
346→    overBudgetCount,
347→    itemCount,
348→  };
349→}
350→
351→export function completeOnboardingState(
352→  baseState: VaultAppState,
353→  input: CompleteOnboardingInput
354→): VaultAppState {
355→  const state = cloneState(baseState);
356→  const normalizedName = input.userName.trim();
357→  const normalizedStore = input.primaryStore.trim();
358→  const normalizedItemName = input.firstItemName.trim();
359→  const normalizedUnit = input.firstItemUnit.trim();
360→  const category = getCategoryById(state.vault, input.firstCategoryId);
361→
362→  if (!category) {
363→    throw new Error('Selected category was not found.');
364→  }
365→
366→  state.user.name = normalizedName;
367→  state.preferences.userName = normalizedName;
368→  state.preferences.hasCompletedOnboarding = true;
369→
370→  const existingStore = state.vault.stores.find(store => store.name.toLowerCase() === normalizedStore.toLowerCase());
371→  const store = existingStore ?? {
372→    id: createId('store'),
373→    name: normalizedStore,
374→    createdAt: new Date().toISOString(),
375→  };
376→
377→  if (!existingStore) {
378→    state.vault.stores.push(store);
379→  }
380→
381→  category.items.unshift({
382→    id: createId('item'),
383→    name: normalizedItemName,
384→    categoryId: category.uid,
385→    priceOptions: [
386→      {
387→        id: createId('priceOption'),
388→        store: store.name,
389→        pricePerUnit: {
390→          priceValue: input.firstItemPrice,
391→          unit: normalizedUnit,
392→        },
393→      },
394→    ],
395→    createdAt: new Date().toISOString(),
396→    isTemporaryShoppingItem: false,
397→    shoppingPrice: null,
398→    shoppingUnit: null,
399→    isOnSale: false,
400→    notes: null,
401→    saleType: null,
402→    discountValue: null,
403→    regularPrice: null,
404→    isDeleted: false,
405→    deletedAt: null,
406→    deletedFromCategoryName: null,
407→    isPlanSuppressed: false,
408→    planSuppressedAt: null,
409→    planSuppressedReason: null,
410→  });
411→
412→  return state;
413→}
