243→export function getItemById(vault: Vault, itemId: string): Item | undefined {
244→  for (const category of vault.categories) {
245→    const match = category.items.find(item => item.id === itemId);
246→    if (match) {
247→      return match;
248→    }
249→  }
250→
251→  return vault.deletedItems.find(item => item.id === itemId);
252→}
