 15→
 16→const steps = ['Welcome', 'Store', 'First item'] as const;
 17→
 18→export function OnboardingFlow() {
 19→  const completeOnboarding = useAppStore(state => state.completeOnboarding);
 20→  const [stepIndex, setStepIndex] = useState(0);
 21→  const [userName, setUserName] = useState('');
 22→  const [storeName, setStoreName] = useState('');
 23→  const [itemName, setItemName] = useState('');
 24→  const [itemPrice, setItemPrice] = useState('4.99');
 25→  const [itemUnit, setItemUnit] = useState('each');
 26→  const [categoryId, setCategoryId] = useState(defaultCategorySeeds[0].slug);
 27→
 28→  const selectedCategory = useMemo(
 29→    () => defaultCategorySeeds.find(category => category.slug === categoryId) ?? defaultCategorySeeds[0],
 30→    [categoryId]
 31→  );
 32→
 33→  const next = async () => {
 34→    if (stepIndex === 0) {
 35→      if (!userName.trim()) {
 36→        Alert.alert('Name required', 'Enter the name Grock should use on your home screen.');
 37→        return;
 38→      }
 39→
 40→      setStepIndex(1);
 41→      return;
 42→    }
 43→
 44→    if (stepIndex === 1) {
 45→      if (!storeName.trim()) {
 46→        Alert.alert('Store required', 'Add the store you use most often.');
 47→        return;
 48→      }
 49→
 50→      setStepIndex(2);
 51→      return;
 52→    }
 53→
 54→    if (!itemName.trim() || !itemUnit.trim()) {
 55→      Alert.alert('First item required', 'Add one item so the vault starts populated.');
 56→      return;
 57→    }
 58→
 59→    const parsedPrice = Number(itemPrice);
 60→    if (!Number.isFinite(parsedPrice) || parsedPrice <= 0) {
 61→      Alert.alert('Invalid price', 'Enter a valid price for the first item.');
 62→      return;
 63→    }
 64→
 65→    await completeOnboarding({
 66→      userName,
 67→      primaryStore: storeName,
 68→      firstItemName: itemName,
