 20→export class AppRepository {
 21→  async loadState(): Promise<VaultAppState> {
 22→    const database = await getDatabase();
 23→    const [result] = await database.executeSql('SELECT payload FROM app_state WHERE id = 1;');
 24→
 25→    if (result.rows.length === 0) {
 26→      const state = createInitialAppState();
 27→      await this.persistState(state);
 28→      return state;
 29→    }
 30→
 31→    const payload = result.rows.item(0).payload as string;
 32→    const state = JSON.parse(payload) as VaultAppState;
 33→
 34→    return this.hydratePreferences(state);
 35→  }
 36→
 37→  async persistState(state: VaultAppState): Promise<VaultAppState> {
 38→    const database = await getDatabase();
 39→    const updatedAt = new Date().toISOString();
 40→    const payload = JSON.stringify(state);
 41→
 42→    await database.executeSql(
 43→      `INSERT INTO app_state (id, payload, updated_at)
 44→       VALUES (1, ?, ?)
 45→       ON CONFLICT(id) DO UPDATE SET payload = excluded.payload, updated_at = excluded.updated_at;`,
 46→      [payload, updatedAt]
 47→    );
 48→
 49→    this.persistPreferences(state);
 50→    return state;
 51→  }
 52→
 53→  async mutate(mutator: (state: VaultAppState) => VaultAppState): Promise<VaultAppState> {
 54→    const current = await this.loadState();
 55→    const next = mutator(cloneState(current));
 56→    return this.persistState(next);
 57→  }
 58→
 59→  async completeOnboarding(input: CompleteOnboardingInput): Promise<VaultAppState> {
 60→    return this.mutate(state => completeOnboardingState(state, input));
 61→  }
 62→
 63→  async updateUserName(name: string): Promise<VaultAppState> {
 64→    return this.mutate(state => {
 65→      state.user.name = name.trim();
 66→      state.preferences.userName = name.trim();
 67→      return state;
 68→    });
 69→  }
 70→
 71→  async addCategory(name: string, emoji: string): Promise<VaultAppState> {
 72→    return this.mutate(state => {
 73→      state.vault.categories.push({
 74→        uid: createId('category'),
 75→        name: name.trim(),
 76→        emoji: emoji.trim() || null,
 77→        sortOrder: state.vault.categories.length,
 78→        colorHex: null,
 79→        isPlanSuppressed: false,
 80→        planSuppressedAt: null,
 81→        planSuppressedReason: null,
 82→        items: [],
 83→      });
 84→      return state;
 85→    });
 86→  }
 87→
 88→  async addItem(input: AddItemInput): Promise<VaultAppState> {
 89→    return this.mutate(state => {
 90→      const category = getCategoryById(state.vault, input.categoryId);
 91→      if (!category) {
 92→        throw new Error('Category not found.');
 93→      }
 94→
 95→      const normalizedStore = input.store.trim();
 96→      const existingStore = state.vault.stores.find(store => store.name.toLowerCase() === normalizedStore.toLowerCase());
 97→      if (!existingStore) {
 98→        state.vault.stores.push({
 99→          id: createId('store'),
100→          name: normalizedStore,
101→          createdAt: new Date().toISOString(),
102→        });
103→      }
104→
105→      category.items.unshift({
106→        id: createId('item'),
107→        name: input.name.trim(),
108→        categoryId: category.uid,
109→        priceOptions: [
110→          {
111→            id: createId('priceOption'),
112→            store: normalizedStore,
113→            pricePerUnit: {
114→              priceValue: input.price,
115→              unit: input.unit.trim(),
116→            },
117→          },
118→        ],
119→        createdAt: new Date().toISOString(),
120→        isTemporaryShoppingItem: false,
121→        shoppingPrice: null,
122→        shoppingUnit: null,
123→        isOnSale: false,
124→        notes: null,
125→        saleType: null,
126→        discountValue: null,
127→        regularPrice: null,
128→        isDeleted: false,
129→        deletedAt: null,
130→        deletedFromCategoryName: null,
131→        isPlanSuppressed: false,
132→        planSuppressedAt: null,
133→        planSuppressedReason: null,
134→      });
135→
136→      return state;
137→    });
138→  }
139→
140→  async createCart(input: CreateCartInput): Promise<VaultAppState> {
141→    return this.mutate(state => {
142→      const cartItems = input.selectedItems.map(selection =>
143→        createCartItemFromVaultItem(state.vault, selection.itemId, selection.quantity, selection.selectedStore)
144→      );
145→
146→      state.vault.carts.unshift({
147→        id: createId('cart'),
148→        name: input.name.trim(),
149→        budget: input.budget,
150→        fulfillmentStatus: 0,
151→        createdAt: new Date().toISOString(),
152→        updatedAt: new Date().toISOString(),
153→        startedAt: null,
154→        completedAt: null,
155→        status: 'planning',
156→        isDeleted: false,
157→        deletedAt: null,
158→        cartItems,
159→      });
160→
161→      return state;
162→    });
163→  }
164→
165→  async toggleCartItemFulfillment(cartId: string, cartItemId: string): Promise<VaultAppState> {
166→    return this.mutate(state => {
167→      const cart = state.vault.carts.find(entry => entry.id === cartId);
168→      const cartItem = cart?.cartItems.find(entry => entry.id === cartItemId);
169→
170→      if (!cart || !cartItem) {
171→        return state;
172→      }
173→
174→      cartItem.isFulfilled = !cartItem.isFulfilled;
175→      cartItem.shouldShowCheckmark = cartItem.isFulfilled;
176→      cartItem.shouldStrikethrough = cartItem.isFulfilled;
177→      cartItem.fulfillmentAnimationState = cartItem.isFulfilled ? 2 : 0;
178→      cartItem.actualQuantity = cartItem.quantity;
179→      cartItem.actualPrice = cartItem.actualPrice ?? cartItem.plannedPrice;
180→      cartItem.actualUnit = cartItem.actualUnit ?? cartItem.plannedUnit;
181→      cartItem.actualStore = cartItem.actualStore ?? cartItem.plannedStore;
182→      cart.updatedAt = new Date().toISOString();
183→      cart.fulfillmentStatus = cart.cartItems.length === 0
184→        ? 0
185→        : cart.cartItems.filter(entry => entry.isFulfilled).length / cart.cartItems.length;
186→
187→      return state;
188→    });
189→  }
190→
191→  async advanceCartStatus(cartId: string): Promise<VaultAppState> {
192→    return this.mutate(state => {
193→      const cart = state.vault.carts.find(entry => entry.id === cartId);
194→      if (!cart) {
195→        return state;
196→      }
197→
198→      const now = new Date().toISOString();
199→      if (cart.status === 'planning') {
200→        cart.status = 'shopping';
201→        cart.startedAt = now;
202→      } else if (cart.status === 'shopping') {
203→        cart.status = 'completed';
204→        cart.completedAt = now;
205→      }
206→
207→      cart.updatedAt = now;
208→      return state;
209→    });
210→  }
211→
212→  async resetState(): Promise<VaultAppState> {
213→    const next = createInitialAppState();
214→    return this.persistState(next);
215→  }
216→
217→  async getDashboard(): Promise<ReturnType<typeof computeDashboardSummary>> {
218→    const state = await this.loadState();
219→    return computeDashboardSummary(state);
220→  }
221→
222→  private hydratePreferences(state: VaultAppState): VaultAppState {
223→    const next = cloneState(state);
224→    next.preferences.hasCompletedOnboarding = storage.getBoolean('hasCompletedOnboarding') ?? next.preferences.hasCompletedOnboarding;
225→    next.preferences.userName = storage.getString('userName') ?? next.preferences.userName;
226→    next.preferences.hasPromptedForNameAfterOnboarding = storage.getBoolean('hasPromptedForNameAfterOnboarding') ?? next.preferences.hasPromptedForNameAfterOnboarding;
227→    next.preferences.hasPromptedForNameAfterVaultCelebration = storage.getBoolean('hasPromptedForNameAfterVaultCelebration') ?? next.preferences.hasPromptedForNameAfterVaultCelebration;
228→    next.preferences.hasShownAddItemGuideAfterName = storage.getBoolean('hasShownAddItemGuideAfterName') ?? next.preferences.hasShownAddItemGuideAfterName;
229→    next.preferences.isPro = storage.getBoolean('isPro') ?? next.preferences.isPro;
230→    next.preferences.freeEditableStoreKeys = storage.getString('freeEditableStoreKeys')
231→      ? JSON.parse(storage.getString('freeEditableStoreKeys') as string) as string[]
232→      : next.preferences.freeEditableStoreKeys;
233→    next.preferences.freePrimaryEditableCartId = storage.getString('freePrimaryEditableCartId') ?? next.preferences.freePrimaryEditableCartId;
234→    next.user.name = next.preferences.userName || next.user.name;
235→    return next;
236→  }
237→
238→  private persistPreferences(state: VaultAppState): void {
239→    storage.set('hasCompletedOnboarding', state.preferences.hasCompletedOnboarding);
240→    storage.set('userName', state.preferences.userName);
241→    storage.set('hasPromptedForNameAfterOnboarding', state.preferences.hasPromptedForNameAfterOnboarding);
242→    storage.set('hasPromptedForNameAfterVaultCelebration', state.preferences.hasPromptedForNameAfterVaultCelebration);
243→    storage.set('hasShownAddItemGuideAfterName', state.preferences.hasShownAddItemGuideAfterName);
244→    storage.set('isPro', state.preferences.isPro);
245→    storage.set('freeEditableStoreKeys', JSON.stringify(state.preferences.freeEditableStoreKeys));
246→
247→    if (state.preferences.freePrimaryEditableCartId) {
248→      storage.set('freePrimaryEditableCartId', state.preferences.freePrimaryEditableCartId);
249→    } else {
250→      storage.remove('freePrimaryEditableCartId');
251→    }
252→  }
253→}
254→
255→export const appRepository = new AppRepository();
