 7→async function migrate(database: any): Promise<void> {
 8→  await database.executeSql(
 9→    `CREATE TABLE IF NOT EXISTS app_state (
10→      id INTEGER PRIMARY KEY NOT NULL CHECK (id = 1),
11→      payload TEXT NOT NULL,
12→      updated_at TEXT NOT NULL
13→    );`
14→  );
15→}
