239→export function getCategoryById(vault: Vault, categoryId: string): Category | undefined {
240→  return vault.categories.find(category => category.uid === categoryId);
241→}
242→
243→export function getItemById(vault: Vault, itemId: string): Item | undefined {
244→  for (const category of vault.categories) {
245→    const match = category.items.find(item => item.id === itemId);
246→    if (match) {
247→      return match;
248→    }
249→  }
250→
251→  return vault.deletedItems.find(item => item.id === itemId);
252→}
253→
254→export function getCurrentPrice(item: Item, store: string): number | null {
255→  return item.priceOptions.find(option => option.store === store)?.pricePerUnit.priceValue ?? null;
256→}
257→
258→export function getCurrentUnit(item: Item, store: string): string | null {
259→  return item.priceOptions.find(option => option.store === store)?.pricePerUnit.unit ?? null;
260→}
261→
262→export function createCartItemFromVaultItem(
263→  vault: Vault,
264→  itemId: string,
265→  quantity: number,
266→  selectedStore?: string | null
267→): CartItem {
268→  const item = getItemById(vault, itemId);
269→  if (!item) {
270→    throw new Error(`Item ${itemId} not found`);
271→  }
272→
273→  const plannedStore = selectedStore ?? item.priceOptions[0]?.store ?? vault.stores[0]?.name ?? 'Unknown Store';
274→
275→  return {
276→    id: createId('cartItem'),
277→    addedAt: new Date().toISOString(),
278→    itemId,
279→    quantity,
280→    isFulfilled: false,
281→    isSkippedDuringShopping: false,
282→    plannedStore,
283→    plannedPrice: getCurrentPrice(item, plannedStore),
284→    plannedUnit: getCurrentUnit(item, plannedStore),
285→    actualStore: null,
286→    actualPrice: null,
287→    actualQuantity: null,
288→    actualUnit: null,
289→    wasEditedDuringShopping: false,
290→    isShoppingOnlyItem: false,
291→    shoppingOnlyName: null,
292→    shoppingOnlyStore: null,
293→    shoppingOnlyPrice: null,
294→    shoppingOnlyUnit: null,
295→    shoppingOnlyCategory: null,
296→    vaultItemNameSnapshot: item.name,
297→    vaultItemCategorySnapshot: getCategoryById(vault, item.categoryId)?.name ?? null,
298→    originalPlanningQuantity: null,
299→    addedDuringShopping: false,
300→    fulfillmentAnimationState: 0,
301→    fulfillmentStartTime: null,
302→    shouldShowCheckmark: false,
303→    shouldStrikethrough: false,
304→    isOnSale: false,
305→    notes: null,
306→    saleType: null,
307→    discountValue: null,
308→    regularPrice: null,
309→  };
310→}
311→
312→export function computeCartTotal(vault: Vault, cart: Cart): number {
313→  return cart.cartItems.reduce((total, cartItem) => {
314→    if (cart.status !== 'planning' && cartItem.isSkippedDuringShopping) {
315→      return total;
316→    }
317→
318→    const item = getItemById(vault, cartItem.itemId);
319→    const fallbackPrice = item ? getCurrentPrice(item, cartItem.plannedStore) ?? 0 : 0;
320→    const price =
321→      cart.status === 'completed'
322→        ? cartItem.actualPrice ?? cartItem.plannedPrice ?? fallbackPrice
323→        : cart.status === 'shopping'
324→          ? cartItem.actualPrice ?? cartItem.plannedPrice ?? fallbackPrice
325→          : cartItem.plannedPrice ?? fallbackPrice;
326→
327→    const quantity = cart.status === 'planning'
328→      ? cartItem.quantity
329→      : cartItem.actualQuantity ?? cartItem.quantity;
330→
331→    return total + price * quantity;
332→  }, 0);
333→}
334→
335→export function computeDashboardSummary(state: VaultAppState): DashboardSummary {
336→  const activeCarts = state.vault.carts.filter(cart => !cart.isDeleted && cart.status !== 'completed');
337→  const completedCarts = state.vault.carts.filter(cart => !cart.isDeleted && cart.status === 'completed');
338→  const totalSpent = completedCarts.reduce((sum, cart) => sum + computeCartTotal(state.vault, cart), 0);
339→  const overBudgetCount = completedCarts.filter(cart => computeCartTotal(state.vault, cart) > cart.budget).length;
340→  const itemCount = state.vault.categories.reduce((sum, category) => sum + category.items.length, 0);
341→
342→  return {
343→    activeCarts,
344→    completedCarts,
345→    totalSpent,
346→    overBudgetCount,
347→    itemCount,
348→  };
349→}
