 1→import SQLite from 'react-native-sqlite-storage';
 2→
 3→SQLite.enablePromise(true);
 4→
 5→let databasePromise: Promise<any> | null = null;
 6→
 7→async function migrate(database: any): Promise<void> {
 8→  await database.executeSql(
 9→    `CREATE TABLE IF NOT EXISTS app_state (
10→      id INTEGER PRIMARY KEY NOT NULL CHECK (id = 1),
11→      payload TEXT NOT NULL,
12→      updated_at TEXT NOT NULL
13→    );`
14→  );
15→}
16→
17→export async function getDatabase(): Promise<any> {
18→  if (!databasePromise) {
19→    databasePromise = SQLite.openDatabase({
20→      name: 'grock-rn.db',
21→      location: 'default',
22→    }).then(async (database: any) => {
23→      await migrate(database);
24→      return database;
25→    });
26→  }
27→
28→  return databasePromise;
29→}
