 1→import Purchases, { CustomerInfo, PurchasesOffering } from 'react-native-purchases';
 2→
 3→export interface SubscriptionSnapshot {
 4→  isConfigured: boolean;
 5→  isPro: boolean;
 6→  isLoading: boolean;
 7→  errorMessage: string | null;
 8→  currentOffering: PurchasesOffering | null;
 9→  customerInfo: CustomerInfo | null;
10→}
11→
12→class SubscriptionService {
13→  private configured = false;
14→
15→  async refresh(previous: SubscriptionSnapshot): Promise<SubscriptionSnapshot> {
16→    if (!this.configured) {
17→      return {
18→        ...previous,
19→        isConfigured: false,
20→        isLoading: false,
21→        errorMessage: 'RevenueCat is not configured in the React Native workspace yet.',
22→        currentOffering: null,
23→      };
24→    }
25→
26→    try {
27→      const [offerings, customerInfo] = await Promise.all([
28→        Purchases.getOfferings(),
29→        Purchases.getCustomerInfo(),
30→      ]);
31→
32→      const currentOffering = offerings.current ?? null;
33→      const isPro = Boolean(customerInfo.entitlements.active.pro);
34→
35→      return {
36→        isConfigured: true,
37→        isLoading: false,
38→        errorMessage: null,
39→        currentOffering,
40→        customerInfo,
41→        isPro,
42→      };
43→    } catch (error) {
44→      return {
45→        ...previous,
46→        isConfigured: this.configured,
47→        isLoading: false,
48→        errorMessage: error instanceof Error ? error.message : 'Failed to refresh subscription state.',
49→      };
50→    }
51→  }
52→}
53→
54→export const subscriptionService = new SubscriptionService();
55→
56→export const emptySubscriptionSnapshot: SubscriptionSnapshot = {
57→  isConfigured: false,
58→  isPro: false,
59→  isLoading: false,
60→  errorMessage: null,
61→  currentOffering: null,
62→  customerInfo: null,
63→};
