    planSuppressedAt: null,
    planSuppressedReason: null,
    items: [],
  }));

  return {
    schemaVersion: 1,
    user: {
      id: createId('user'),
      name: 'Default User',
    },
    vault: {
      uid: createId('vault'),
      categories,
      carts: [],
      stores: [],
      deletedItems: [],
      deletedCarts: [],
      deletedCartItemSnapshots: [],
