export default App;

const styles = {
  root: {
    flex: 1,
  },
};

import { NativeStackScreenProps } from '@react-navigation/native-stack';
import React, { useMemo, useState } from 'react';
import {
  Pressable,
  ScrollView,
  StyleSheet,
  Text,
  TextInput,
  View,
} from 'react-native';

import { computeCartTotal, computeDashboardSummary } from '../../domain/models';
import { formatCurrency } from '../../lib/format';
import { RootStackParamList } from '../../navigation/types';
import { useAppStore } from '../../state/useAppStore';
import { colors } from '../../theme/colors';

type Props = NativeStackScreenProps<RootStackParamList, 'Home'>;
type HomeTab = 'active' | 'completed' | 'insights';

export function HomeScreen({ navigation }: Props) {
  const appState = useAppStore(state => state.appState);
  const draftSelections = useAppStore(state => state.draftSelections);
  const createCart = useAppStore(state => state.createCart);
  const [tab, setTab] = useState<HomeTab>('active');
  const [cartName, setCartName] = useState('');
  const [budget, setBudget] = useState('120');

  const summary = useMemo(() => (appState ? computeDashboardSummary(appState) : null), [appState]);

  if (!appState || !summary) {
    return null;
  }

  const selectedItems = Object.entries(draftSelections).map(([itemId, quantity]) => ({
    itemId,
    quantity,
  }));

  const handleCreateCart = async () => {
    if (!selectedItems.length) {
      return;
    }

    const parsedBudget = Number(budget);
    if (!cartName.trim() || !Number.isFinite(parsedBudget)) {
      return;
    }

    await createCart({
      name: cartName,
      budget: parsedBudget,
      selectedItems,
    });

    setCartName('');
  };

  return (
    <ScrollView style={styles.screen} contentContainerStyle={styles.content}>
      <View style={styles.hero}>
        <Text style={styles.eyebrow}>Grock React Native</Text>
        <Text style={styles.title}>Hi {appState.user.name || 'there'}</Text>
        <Text style={styles.subtitle}>
          The new bare React Native shell is wired to Grock&apos;s local vault, carts,
          onboarding state, and subscription placeholder.
        </Text>
      </View>

      <View style={styles.actionRow}>
        <ActionButton label="Vault" onPress={() => navigation.navigate('Vault')} />
        <ActionButton label="History" onPress={() => navigation.navigate('History')} />
        <ActionButton label="Menu" onPress={() => navigation.navigate('Menu')} />
        <ActionButton label="Paywall" onPress={() => navigation.navigate('Paywall')} />
      </View>

      <View style={styles.card}>
        <Text style={styles.cardTitle}>Quick cart from vault selection</Text>
        <Text style={styles.cardCopy}>
          Select items in Vault, then create a planning cart here.
        </Text>
        <TextInput
          style={styles.input}
          value={cartName}
          onChangeText={setCartName}
          placeholder="Weekend groceries"
          placeholderTextColor={colors.mutedInk}
        />
        <TextInput
          style={styles.input}
          value={budget}
          onChangeText={setBudget}
          placeholder="Budget"
          placeholderTextColor={colors.mutedInk}
          keyboardType="decimal-pad"
        />
        <Pressable
          style={[styles.primaryButton, !selectedItems.length && styles.buttonDisabled]}
          onPress={() => {
            handleCreateCart().catch(() => undefined);
          }}
          disabled={!selectedItems.length}
        >
          <Text style={styles.primaryButtonText}>
            Create cart from {selectedItems.length} selected item{selectedItems.length === 1 ? '' : 's'}
          </Text>
        </Pressable>
      </View>

      <View style={styles.summaryRow}>
        <SummaryCard label="Active carts" value={String(summary.activeCarts.length)} />
        <SummaryCard label="Items in vault" value={String(summary.itemCount)} />
        <SummaryCard label="Completed spend" value={formatCurrency(summary.totalSpent)} />
      </View>

      <View style={styles.tabRow}>
        {(['active', 'completed', 'insights'] as HomeTab[]).map(option => (
          <Pressable
            key={option}
            style={[styles.tabButton, tab === option && styles.tabButtonActive]}
            onPress={() => setTab(option)}
          >
            <Text style={[styles.tabButtonText, tab === option && styles.tabButtonTextActive]}>
              {option.charAt(0).toUpperCase() + option.slice(1)}
            </Text>
          </Pressable>
        ))}
      </View>

      {tab === 'active' ? (
        <View style={styles.section}>
          {summary.activeCarts.length ? (
            summary.activeCarts.map(cart => (
              <Pressable
                key={cart.id}
                style={styles.listCard}
                onPress={() => navigation.navigate('CartDetail', { cartId: cart.id })}
              >
                <View>
                  <Text style={styles.listTitle}>{cart.name}</Text>
                  <Text style={styles.listMeta}>
                    {cart.cartItems.length} items • Budget {formatCurrency(cart.budget)}
                  </Text>
                </View>
                <Text style={styles.listValue}>{formatCurrency(computeCartTotal(appState.vault, cart))}</Text>
              </Pressable>
            ))
          ) : (
            <EmptyState
              title="No active carts"
              copy="Select items in Vault, then build your first planning cart from the quick-create card above."
            />
          )}
        </View>
      ) : null}

      {tab === 'completed' ? (
        <View style={styles.section}>
          {summary.completedCarts.length ? (
            summary.completedCarts.map(cart => (
              <Pressable
                key={cart.id}
                style={styles.listCard}
                onPress={() => navigation.navigate('CartDetail', { cartId: cart.id })}
              >
                <View>
                  <Text style={styles.listTitle}>{cart.name}</Text>
                  <Text style={styles.listMeta}>
                    Completed {cart.completedAt ? new Date(cart.completedAt).toLocaleDateString() : 'recently'}
                  </Text>
                </View>
                <Text style={styles.listValue}>{formatCurrency(computeCartTotal(appState.vault, cart))}</Text>
              </Pressable>
            ))
          ) : (
            <EmptyState
              title="No completed trips yet"
              copy="Move a cart from planning to shopping and finish the trip to start building history."
            />
          )}
        </View>
      ) : null}

      {tab === 'insights' ? (
        <View style={styles.section}>
          <View style={styles.card}>
            <Text style={styles.cardTitle}>Trip insights</Text>
            <Text style={styles.cardCopy}>
              {summary.overBudgetCount} completed cart{summary.overBudgetCount === 1 ? '' : 's'} finished over budget.
            </Text>
            <Text style={styles.cardCopy}>
              Average spend per completed cart:{' '}
              {summary.completedCarts.length
                ? formatCurrency(summary.totalSpent / summary.completedCarts.length)
                : formatCurrency(0)}
            </Text>
          </View>
        </View>
      ) : null}
    </ScrollView>
  );
}

function ActionButton({ label, onPress }: { label: string; onPress: () => void }) {
  return (
    <Pressable style={styles.actionButton} onPress={onPress}>
      <Text style={styles.actionButtonText}>{label}</Text>
    </Pressable>
  );
}

function SummaryCard({ label, value }: { label: string; value: string }) {
  return (
    <View style={styles.summaryCard}>
      <Text style={styles.summaryLabel}>{label}</Text>
