              <Text style={styles.itemName}>{item.vaultItemNameSnapshot ?? item.shoppingOnlyName ?? 'Item'}</Text>
              <Text style={styles.itemCopy}>
                {item.quantity} x {formatCurrency(item.plannedPrice ?? 0)} • {item.plannedStore}
              </Text>
            </View>
            <Pressable
              style={[styles.fulfillButton, item.isFulfilled && styles.fulfillButtonActive]}
              onPress={() => {
                toggleCartItemFulfillment(cart.id, item.id).catch(() => undefined);
              }}
            >
              <Text style={[styles.fulfillButtonText, item.isFulfilled && styles.fulfillButtonTextActive]}>
                {item.isFulfilled ? 'Fulfilled' : 'Mark done'}
              </Text>
            </Pressable>
          </View>
        ))}
      </View>
    </ScrollView>
  );
}

